import type {
  ComponentPropsWithRef,
  ElementType,
  ReactNode,
  FunctionComponent,
  ComponentPropsWithoutRef,
  PropsWithChildren,
  ComponentType,
} from 'react';
import type { ImageProps as AndesImageProps } from '@andes/image';
import type {
  VisuallyHiddenComponentTypes,
  VisuallyHiddenProps,
  VisuallyHiddenFocusableProps,
} from '@andes/visually-hidden';
import type { CloseListenerProps } from '@andes/close-listener';

interface ElementTypeMap<DC extends ElementType, Props = object> {
  defaultElement: DC;
  props: Props;
}

interface OverridableType {
  defaultElement: ElementType;
  props: object;
}

type BaseProps<TypeMap extends OverridableType> = TypeMap['props'];

type DefaultElementProp<TypeMap extends OverridableType> =
  TypeMap['defaultElement'];

type OverridePropsWithRef<
  TypeMap extends OverridableType,
  CustomComponent extends ElementType,
> = BaseProps<TypeMap> &
  Omit<
    ComponentPropsWithRef<CustomComponent>,
    keyof Omit<BaseProps<TypeMap>, 'ref'>
  >;

type OverridePropsWithoutRef<
  TypeMap extends OverridableType,
  CustomComponent extends ElementType,
> = BaseProps<TypeMap> &
  Omit<ComponentPropsWithoutRef<CustomComponent>, keyof BaseProps<TypeMap>>;

type DefaultComponentProps<TypeMap extends OverridableType> =
  OverridePropsWithRef<TypeMap, DefaultElementProp<TypeMap>> & {
    component?: DefaultElementProp<TypeMap>;
  };

interface WithProps {
  displayName?: string;
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  [key: string]: any;
}

interface OverrideComponent<
  TypeMap extends OverridableType,
  Element extends ElementType = ElementType,
> extends WithProps {
  <Component extends Element>(
    props: OverridePropsWithRef<TypeMap, Component> & {
      component: Component;
    },
  ): ReactNode;
  (props: DefaultComponentProps<TypeMap>): ReactNode;
}

interface OverrideFunctionalComponent<
  TypeMap extends OverridableType,
  Element extends ElementType = DefaultElementProp<TypeMap>,
> extends WithProps {
  <Component extends Element>(
    props: OverridePropsWithoutRef<TypeMap, Component> & {
      component?: Component;
    },
  ): ReactNode;
}

type BasicI18n = {
  pgettext: (namespace: string, text: string) => string;
};

export type BasicI18nProps = BasicI18n;

// Code taken from TS Issue requesting XOR utility type, which we need
// https://github.com/Microsoft/TypeScript/issues/14094#issuecomment-373782604
/** @internal */
export type Without<T, U> = { [P in Exclude<keyof T, keyof U>]?: never };

/** @internal */
export type XOR<T, U> = T | U extends object
  ? (T & Without<U, T>) | (U & Without<T, U>)
  : T | U;

/** @internal */
export type PolymorphicExoticComponent<
  DC extends ElementType,
  Props extends object,
> = OverrideComponent<ElementTypeMap<DC, Props>>;

/** @internal */
export type PolymorphicExoticComponentRestricted<
  DC extends Elements,
  Props extends object,
  Elements extends ElementType,
> = OverrideComponent<ElementTypeMap<DC, Props>, Elements>;

/** @internal */
export type PolymorphicComponent<
  DC extends ElementType,
  Props extends object,
> = OverrideFunctionalComponent<ElementTypeMap<DC, Props>>;

/** @internal */
export type PolymorphicComponentRestricted<
  DC extends ElementType,
  Props extends object,
  Elements extends ElementType,
> = OverrideFunctionalComponent<ElementTypeMap<DC, Props>, Elements>;

